  'var noSigMsg = "From: a@example.com\\r\\nTo: b@example.com\\r\\n\\r\\nbody\\r\\n";',
  'var rv = await b.mail.dkim.verify(noSigMsg);',
  '// rv → [{ result: "none", errors: ["no DKIM-Signature headers"] }]',
  '</code></pre>',

  '<h2 id="spf-verify">b.mail.spf.verify(opts) <a class="anchor" href="#spf-verify">#</a></h2>',
  '<pre><code class="language-javascript">{',
  '  ip:        string,                                // sender IP (required)',
  '  mailFrom:  string,                                // SMTP MAIL FROM address',
  '  helo:      string,                                // EHLO/HELO host (fallback when no mailFrom)',
  '  dnsLookup: async (qname, type) => txtRecords,    // optional',
  '}</code></pre>',
  '<p>RFC 7208 SPF check with <code>ip4</code> / <code>ip6</code> / <code>include</code> / <code>all</code> mechanisms. Recursive include resolution with the 10-DNS-lookup ceiling per §4.6.4. Returns <code>{ result, domain, explanation, lookupCount }</code> where result is one of <code>pass</code> / <code>fail</code> / <code>softfail</code> / <code>neutral</code> / <code>none</code> / <code>temperror</code> / <code>permerror</code>. The <code>a</code> / <code>mx</code> / <code>exists</code> / <code>ptr</code> / <code>redirect</code> mechanisms surface as <code>permerror</code> with a diagnosis — operators with those wire their own resolver.</p>',
  '<pre><code class="language-javascript">// Mocked DNS that returns no SPF record — produces a "none" verdict.',
  '// In production, omit dnsLookup and node:dns/promises is used.',
  'var dnsLookup = async function () { var e = new Error(); e.code = "ENOTFOUND"; throw e; };',
  'var rv = await b.mail.spf.verify({',
  '  ip:        "192.0.2.5",',
  '  mailFrom:  "alice@example.com",',
  '  dnsLookup: dnsLookup,',
  '});',
  '// rv → { result: "none", domain: "example.com", explanation: "no SPF record at example.com" }',
