  '<h2 id="dmarc-evaluate">b.mail.dmarc.evaluate(opts) <a class="anchor" href="#dmarc-evaluate">#</a></h2>',
  '<pre><code class="language-javascript">{',
  '  from:      string,                                // From: header email address (required)',
  '  spf:       { result, domain },                    // from b.mail.spf.verify',
